using System;
using System.Diagnostics;
using System.IO;
using System.IO.Compression;
using System.Runtime.InteropServices;
using System.Threading;
using System.Threading.Tasks;

using SourceGit.Models;

namespace SourceGit.Services;

/// <summary>
/// Orchestrates UE BuildGraph for staging and packaging editor/game binaries.
/// Uses a structured StageResult (not string parsing) per council review finding C-1.
/// Accepts UgsConfig in constructor per finding H-2 (no per-call LoadConfig).
/// Validates RunUAT path existence per finding M-2.
/// </summary>
public class BuildGraphService
{
    private readonly string _enginePath;
    private readonly string _repoPath;
    private readonly UgsConfig _config;

    public BuildGraphService(string enginePath, string repoPath, UgsConfig config)
    {
        _enginePath = enginePath;
        _repoPath = repoPath;
        _config = config;
    }

    /// <summary>
    /// Run BuildGraph to compile + stage editor/game binaries.
    /// Returns StageResult with StagingDirectory on success (fixes C-1).
    /// </summary>
    public async Task<StageResult> StageAsync(
        string editorTarget,
        string platform,
        string configuration,
        bool includePdb,
        IProgress<string> log,
        CancellationToken ct,
        TimeSpan? timeout = null)
    {
        var runUat = GetRunUatPath();

        // Validate RunUAT exists (fixes M-2)
        if (!File.Exists(runUat))
            return new StageResult(BuildStatus.Failed, "stage", string.Empty,
                $"RunUAT not found at {runUat}. Is this a source build?");

        var args = $"BuildGraph " +
                   $"-Script=\"Engine/Build/Graph/Examples/BuildEditorAndTools.xml\" " +
                   $"-Target=\"Copy to Staging Directory\" " +
                   $"-set:EditorTarget={editorTarget} " +
                   $"-set:ArchiveStream={editorTarget} ";

        if (!includePdb)
            args += "-set:ExcludePdb=true ";

        var sw = Stopwatch.StartNew();
        Process process = null!;
        CancellationTokenSource? linkedCts = null;

        try
        {
            linkedCts = CancellationTokenSource.CreateLinkedTokenSource(ct);
            linkedCts.CancelAfter(timeout ?? TimeSpan.FromHours(2));

            var psi = new ProcessStartInfo
            {
                FileName = runUat,
                Arguments = args,
                WorkingDirectory = _enginePath,
                UseShellExecute = false,
                CreateNoWindow = true,
                RedirectStandardOutput = true,
                RedirectStandardError = true
            };

            process = new Process { StartInfo = psi };
            process.Start();

            var stdout = await process.StandardOutput.ReadToEndAsync(linkedCts.Token);
            var stderr = await process.StandardError.ReadToEndAsync(linkedCts.Token);
            await process.WaitForExitAsync(linkedCts.Token);

            sw.Stop();
            log.Report(stdout);
            if (!string.IsNullOrWhiteSpace(stderr)) log.Report(stderr);

            if (process.ExitCode != 0)
                return new StageResult(BuildStatus.Failed, "stage", string.Empty,
                    $"BuildGraph failed (exit {process.ExitCode})", sw.Elapsed);

            var stagingDir = GetStagingDirectory();
            if (!Directory.Exists(stagingDir))
                return new StageResult(BuildStatus.Failed, "stage", string.Empty,
                    $"Staging directory not found: {stagingDir}");

            return new StageResult(BuildStatus.Success, "stage", stagingDir,
                $"Staged to {stagingDir}", sw.Elapsed);
        }
        catch (OperationCanceledException)
        {
            KillProcess(process);
            sw.Stop();
            return new StageResult(BuildStatus.Cancelled, "stage", string.Empty,
                "Stage cancelled", sw.Elapsed);
        }
        catch (Exception ex)
        {
            KillProcess(process);
            sw.Stop();
            Native.OS.LogException(ex);
            return new StageResult(BuildStatus.Failed, "stage", string.Empty,
                $"Stage error: {ex.Message}", sw.Elapsed);
        }
        finally
        {
            linkedCts?.Dispose();
            process?.Dispose();
        }
    }

    /// <summary>
    /// Create a zip from the staging directory. Returns the zip file path.
    /// If cancellation is requested mid-zip, the partial file is deleted (fixes M-4).
    /// </summary>
    public async Task<string> CreateZipAsync(
        string stagingDir,
        string outputPath,
        bool excludePdb,
        IProgress<string> log,
        CancellationToken ct)
    {
        log.Report($"Creating zip: {outputPath}");

        await Task.Run(() =>
        {
            if (File.Exists(outputPath))
                File.Delete(outputPath);

            // Ensure output directory exists
            var outputDir = Path.GetDirectoryName(outputPath);
            if (!string.IsNullOrEmpty(outputDir) && !Directory.Exists(outputDir))
                Directory.CreateDirectory(outputDir);

            var compression = GetCompressionLevel();

            using var archive = ZipFile.Open(outputPath, ZipArchiveMode.Create);

            foreach (var file in Directory.GetFiles(stagingDir, "*", SearchOption.AllDirectories))
            {
                if (ct.IsCancellationRequested)
                {
                    // ZipArchive doesn't support mid-write cancellation.
                    // Delete partial zip and throw (fixes M-4).
                    archive.Dispose();
                    if (File.Exists(outputPath))
                        File.Delete(outputPath);
                    ct.ThrowIfCancellationRequested();
                }

                if (excludePdb && file.EndsWith(".pdb", StringComparison.OrdinalIgnoreCase))
                    continue;

                var relativePath = Path.GetRelativePath(stagingDir, file);
                archive.CreateEntryFromFile(file, relativePath, compression);
            }
        }, ct);

        return outputPath;
    }

    private static CompressionLevel GetCompressionLevel() => CompressionLevel.Optimal;

    private string GetRunUatPath() =>
        RuntimeInformation.IsOSPlatform(OSPlatform.Windows)
            ? Path.Combine(_enginePath, "Engine", "Build", "BatchFiles", "RunUAT.bat")
            : Path.Combine(_enginePath, "Engine", "Build", "BatchFiles", "RunUAT.sh");

    /// <summary>
    /// Get staging directory from config (fixes H-2: uses cached _config, not LoadConfig per call).
    /// </summary>
    private string GetStagingDirectory()
    {
        var outputDir = _config.BuildDefaults?.OutputDirectory ?? "Saved/StagedBuilds";
        return Path.GetFullPath(Path.Combine(_repoPath, outputDir));
    }

    private static void KillProcess(Process process)
    {
        if (process is { HasExited: false })
        {
            try { process.Kill(entireProcessTree: true); } catch { /* best effort */ }
        }
    }
}

using System;
using System.Diagnostics;
using System.Runtime.InteropServices;
using System.Threading;
using System.Threading.Tasks;

using SourceGit.Models;

namespace SourceGit.Services;

/// <summary>
/// Executes UBT build targets or custom scripts. Has CancellationToken support
/// and configurable process timeout (default: 2 hours for UE builds).
/// Fixes RC-7.
/// </summary>
public class BuildService
{
    private static readonly TimeSpan DefaultTimeout = TimeSpan.FromHours(2);

    private readonly string _repoPath;
    private readonly string _enginePath;

    public BuildService(string repoPath, string enginePath)
    {
        _repoPath = repoPath;
        _enginePath = enginePath;
    }

    /// <summary>
    /// Execute a single build step. Streams output to progress.
    /// </summary>
    public async Task<BuildResult> ExecuteStepAsync(
        UgsBuildStep step,
        IProgress<string> log,
        CancellationToken ct,
        TimeSpan? timeout = null)
    {
        log.Report($"\n> Build: {step.DisplayName} ({step.Platform} {step.Configuration})...");

        var sw = Stopwatch.StartNew();

        try
        {
            var (fileName, arguments) = GetBuildCommand(step);

            var psi = new ProcessStartInfo
            {
                FileName = fileName,
                Arguments = arguments,
                WorkingDirectory = _repoPath,
                UseShellExecute = false,
                CreateNoWindow = true,
                RedirectStandardOutput = true,
                RedirectStandardError = true
            };

            using var process = new Process { StartInfo = psi };

            using var linkedCts = CancellationTokenSource.CreateLinkedTokenSource(ct);
            linkedCts.CancelAfter(timeout ?? DefaultTimeout);

            process.Start();

            var stdoutTask = ConsumeOutputAsync(process.StandardOutput, log, linkedCts.Token);
            var stderrTask = ConsumeOutputAsync(process.StandardError, log, linkedCts.Token);

            try
            {
                await process.WaitForExitAsync(linkedCts.Token);
            }
            catch (OperationCanceledException) when (!ct.IsCancellationRequested)
            {
                // Timeout — kill the process
                try { process.Kill(entireProcessTree: true); } catch { /* ignore */ }
                sw.Stop();
                return new BuildResult(BuildStatus.Timeout, step.Id,
                    $"Build timed out after {timeout ?? DefaultTimeout}", sw.Elapsed);
            }

            await Task.WhenAll(stdoutTask, stderrTask);
            sw.Stop();

            if (process.ExitCode == 0)
            {
                log.Report($"Build completed successfully ({sw.Elapsed.TotalSeconds:F1}s)");
                return new BuildResult(BuildStatus.Success, step.Id,
                    $"Build succeeded", sw.Elapsed);
            }

            return new BuildResult(BuildStatus.Failed, step.Id,
                $"Build failed with exit code {process.ExitCode}", sw.Elapsed);
        }
        catch (OperationCanceledException)
        {
            sw.Stop();
            return new BuildResult(BuildStatus.Cancelled, step.Id,
                "Build cancelled", sw.Elapsed);
        }
        catch (Exception ex)
        {
            sw.Stop();
            Native.OS.LogException(ex);
            return new BuildResult(BuildStatus.Failed, step.Id,
                $"Build error: {ex.Message}", sw.Elapsed);
        }
    }

    /// <summary>
    /// Execute steps in order. Stops on first failure.
    /// </summary>
    public async Task<BuildResult> ExecuteAllAsync(
        System.Collections.Generic.List<UgsBuildStep> steps,
        IProgress<string> log,
        CancellationToken ct)
    {
        foreach (var step in steps.OrderBy(s => s.OrderIndex))
        {
            var result = await ExecuteStepAsync(step, log, ct);
            if (result.Status != BuildStatus.Success)
                return result;
        }
        return new BuildResult(BuildStatus.Success, "all", "All build steps completed successfully");
    }

    private (string FileName, string Arguments) GetBuildCommand(UgsBuildStep step)
    {
        // Custom script path takes priority
        if (!string.IsNullOrEmpty(step.ScriptPath))
        {
            var fullPath = Path.IsPathRooted(step.ScriptPath)
                ? step.ScriptPath
                : Path.GetFullPath(Path.Combine(_repoPath, step.ScriptPath));

            return (fullPath, string.Empty);
        }

        // UBT build target
        var runUatPath = GetRunUatPath();
        var arguments = $"BuildCookRun " +
                        $"-project=\"{GetProjectFile()}\" " +
                        $"-platform={step.Platform} " +
                        $"-clientconfig={step.Configuration} " +
                        $"-serverconfig={step.Configuration} " +
                        $"-build " +
                        $"-cook " +
                        $"-stage " +
                        $"-pak " +
                        $"-archive " +
                        $"-archivedirectory=\"{Path.Combine(_repoPath, "Saved", "StagedBuilds")}\"";

        return (runUatPath, arguments);
    }

    private string GetRunUatPath()
    {
        var batchDir = Path.Combine(_enginePath, "Engine", "Build", "BatchFiles");

        if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
            return Path.Combine(batchDir, "RunUAT.bat");

        return Path.Combine(batchDir, "RunUAT.sh");
    }

    private string GetProjectFile()
    {
        var uprojectFiles = Directory.GetFiles(_repoPath, "*.uproject", SearchOption.TopDirectoryOnly);
        return uprojectFiles.Length > 0
            ? uprojectFiles[0]
            : Path.Combine(_repoPath, "Project.uproject");
    }

    private static async Task ConsumeOutputAsync(
        System.IO.StreamReader reader, IProgress<string> log, CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            var line = await reader.ReadLineAsync(ct);
            if (line == null) break;
            log.Report(line);
        }
    }
}

public enum BuildStatus
{
    Success,
    Failed,
    Cancelled,
    Timeout
}

public record BuildResult(
    BuildStatus Status,
    string StepId,
    string Message,
    TimeSpan? Duration = null
);

using System;
using System.Collections.Generic;
using System.IO;
using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.RegularExpressions;

using SourceGit.Models;

namespace SourceGit.Services;

/// <summary>
/// Reads and writes .unrealsync.json config files with environment variable expansion,
/// version migration, and user-local state persistence.
/// </summary>
public static class ConfigService
{
    private const string ConfigFileName = ".unrealsync.json";
    private const string LocalConfigDir = ".unrealsync";
    private const string LocalConfigFile = "local.json";

    private static readonly Regex EnvVarRegex = new(@"\$\{(\w+)\}", RegexOptions.Compiled);
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        ReadCommentHandling = JsonCommentHandling.Skip,
        PropertyNameCaseInsensitive = true,
        WriteIndented = true
    };

    static ConfigService()
    {
        JsonOptions.TypeInfoResolverChain.Add(UnrealSyncJsonContext.Default);
    }

    /// <summary>
    /// Load the team-shared config from repo root. Returns an empty config if file doesn't exist.
    /// </summary>
    public static UgsConfig LoadConfig(string repoPath)
    {
        var configPath = GetConfigPath(repoPath);
        if (!File.Exists(configPath))
            return new UgsConfig();

        var json = File.ReadAllText(configPath);
        var config = JsonSerializer.Deserialize(json, UnrealSyncJsonContext.Default.UgsConfig)
            ?? new UgsConfig();

        // Validate version — refuse unknown versions
        if (config.Version > 1)
            throw new InvalidOperationException(
                $"Unknown .unrealsync.json version {config.Version}. Supported: 1.");

        // Expand environment variables in all string fields
        ExpandEnvVarsInConfig(config);

        return config;
    }

    /// <summary>
    /// Load user-local state from .unrealsync/local.json (gitignored).
    /// </summary>
    public static UgsWorkspaceState LoadLocalState(string repoPath)
    {
        var localPath = GetLocalConfigPath(repoPath);
        if (!File.Exists(localPath))
            return new UgsWorkspaceState();

        var json = File.ReadAllText(localPath);
        return JsonSerializer.Deserialize(json, UnrealSyncJsonContext.Default.UgsWorkspaceState)
            ?? new UgsWorkspaceState();
    }

    /// <summary>
    /// Save user-local state to .unrealsync/local.json.
    /// </summary>
    public static void SaveLocalState(string repoPath, UgsWorkspaceState state)
    {
        var localPath = GetLocalConfigPath(repoPath);
        var dir = Path.GetDirectoryName(localPath);
        if (!string.IsNullOrEmpty(dir) && !Directory.Exists(dir))
            Directory.CreateDirectory(dir);

        var json = JsonSerializer.Serialize(state, UnrealSyncJsonContext.Default.UgsWorkspaceState);
        File.WriteAllText(localPath, json);
    }

    /// <summary>
    /// Resolve a ${NAME} environment variable reference. Unknown vars return empty string.
    /// </summary>
    public static string ResolveEnvVars(string value)
    {
        if (string.IsNullOrEmpty(value)) return value;
        return EnvVarRegex.Replace(value, match =>
            Environment.GetEnvironmentVariable(match.Groups[1].Value) ?? string.Empty);
    }

    private static string GetConfigPath(string repoPath) =>
        Path.Combine(repoPath, ConfigFileName);

    private static string GetLocalConfigPath(string repoPath) =>
        Path.Combine(repoPath, LocalConfigDir, LocalConfigFile);

    private static void ExpandEnvVarsInConfig(UgsConfig config)
    {
        // Expand env vars in CI config
        if (config.Ci?.TeamCity is { } tc)
        {
            if (tc.AccessToken != null)
                tc = tc with { AccessToken = ResolveEnvVars(tc.AccessToken) };
        }
    }
}

/// <summary>
/// Source-generated JSON context for all UnrealSync types.
/// Required for AOT compatibility when DISABLE_PLUGINS is not set.
/// </summary>
[JsonSerializable(typeof(UgsConfig))]
[JsonSerializable(typeof(UgsWorkspaceState))]
[JsonSerializable(typeof(UProjectMeta))]
[JsonSerializable(typeof(UgsBuildStep))]
internal partial class UnrealSyncJsonContext : JsonSerializerContext { }

using System;
using System.Diagnostics;
using System.IO;
using System.Runtime.InteropServices;
using System.Threading;
using System.Threading.Tasks;

namespace SourceGit.Services;

/// <summary>
/// Finds and launches the Unreal Engine editor. Cross-platform.
/// Separate from BuildService to keep concerns clean.
/// </summary>
public class EditorLauncher
{
    private readonly string _enginePath;

    public EditorLauncher(string enginePath)
    {
        _enginePath = enginePath;
    }

    public static string EditorBinaryName => RuntimeInformation.IsOSPlatform(OSPlatform.Windows)
        ? "UnrealEditor.exe"
        : RuntimeInformation.IsOSPlatform(OSPlatform.OSX)
            ? "UnrealEditor.app/Contents/MacOS/UnrealEditor"
            : "UnrealEditor";

    /// <summary>
    /// Find the editor executable for the given engine path.
    /// Tries UE5 first, falls back to UE4 (fixes DG-13).
    /// </summary>
    public string? FindEditorPath()
    {
        var ue5Path = Path.Combine(_enginePath, "Engine", "Binaries",
            GetPlatformBinaryDir(), EditorBinaryName);

        if (File.Exists(ue5Path))
            return ue5Path;

        // Try UE4 fallback
        var ue4Name = EditorBinaryName.Replace("UnrealEditor", "UE4Editor");
        var ue4Path = Path.Combine(_enginePath, "Engine", "Binaries",
            GetPlatformBinaryDir(), ue4Name);

        return File.Exists(ue4Path) ? ue4Path : null;
    }

    /// <summary>
    /// Launch the editor with the given project and arguments.
    /// </summary>
    public async Task<Process?> LaunchAsync(
        string projectPath, string? arguments = null, CancellationToken ct = default)
    {
        var editorPath = FindEditorPath();
        if (editorPath == null)
            throw new FileNotFoundException($"Could not find editor binary in {_enginePath}");

        var args = $"\"{projectPath}\"";
        if (!string.IsNullOrEmpty(arguments))
            args += $" {arguments}";

        var psi = new ProcessStartInfo
        {
            FileName = editorPath,
            Arguments = args,
            UseShellExecute = true
        };

        return Process.Start(psi);
    }

    private static string GetPlatformBinaryDir() =>
        RuntimeInformation.IsOSPlatform(OSPlatform.Windows) ? "Win64"
        : RuntimeInformation.IsOSPlatform(OSPlatform.OSX) ? "Mac"
        : "Linux";
}

using System;
using System.Collections.Generic;
using System.IO;
using System.Runtime.InteropServices;

using SourceGit.Models;

namespace SourceGit.Services;

/// <summary>
/// Multi-source engine detection. Follows UGS's approach of checking
/// multiple sources to find the Unreal Engine installation path.
/// Cross-platform (Windows, macOS, Linux). Fixes RC-6, DG-13.
/// </summary>
public static class EngineDetector
{
    /// <summary>
    /// Detect the engine path for a UE project. Returns null if not found.
    /// </summary>
    /// <param name="meta">Parsed .uproject metadata</param>
    /// <param name="repoPath">Repository root path</param>
    /// <returns>Engine installation directory path, or null</returns>
    public static string? Detect(UProjectMeta meta, string repoPath)
    {
        // 1. Config override (.unrealsync.json engine.path)
        var config = ConfigService.LoadConfig(repoPath);
        if (config.Engine?.Path != null)
        {
            var configPath = ResolveRelativePath(repoPath, config.Engine.Path);
            if (IsValidEngineRoot(configPath))
                return configPath;
        }

        // 2. Environment variable
        var envPaths = new[] { "UNREAL_ENGINE_PATH", "UE_ROOT" };
        foreach (var env in envPaths)
        {
            var envPath = Environment.GetEnvironmentVariable(env);
            if (!string.IsNullOrEmpty(envPath) && IsValidEngineRoot(envPath))
                return envPath;
        }

        // 3. UProject EngineAssociation
        if (!string.IsNullOrEmpty(meta.EngineAssociation))
        {
            var association = meta.EngineAssociation.Trim();

            // GUID (e.g., {42454BA6-4990-A48A-898C-84AA3B434615})
            if (association.StartsWith('{') && association.EndsWith('}'))
            {
                if (TryRegistryLookup(association, out var registryPath))
                    return registryPath;
            }
            // Version string (e.g., "5.4")
            else if (Version.TryParse(association, out var version))
            {
                var versionStr = $"{version.Major}.{version.Minor}";
                foreach (var installPath in GetKnownInstallPaths(versionStr))
                {
                    if (IsValidEngineRoot(installPath))
                        return installPath;
                }
            }
            // Relative/absolute path (e.g., "../UE5")
            else
            {
                var uprojectDir = GetUProjectDirectory(repoPath, meta);
                var resolved = ResolveRelativePath(uprojectDir ?? repoPath, association);
                if (IsValidEngineRoot(resolved))
                    return resolved;
            }
        }

        // 4. Known install paths (scan for UE5.* and UE4.*)
        foreach (var knownPath in GetKnownInstallPaths(null))
        {
            if (IsValidEngineRoot(knownPath))
                return knownPath;
        }

        // 5. Relative probe (../UE5, ../UE4, ../UnrealEngine, ../Engine)
        var relativeProbes = new[] { "../UE5", "../UE4", "../UnrealEngine", "../Engine" };
        foreach (var probe in relativeProbes)
        {
            var probePath = ResolveRelativePath(repoPath, probe);
            if (IsValidEngineRoot(probePath))
                return probePath;
        }

        // 6. Registry (Windows) — broad HKCU and HKLM scans
        if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
        {
            // Try common registry keys for installed builds
            if (TryRegistryLookup(null, out var regPath))
                return regPath;
        }

        return null;
    }

    /// <summary>
    /// Validate a candidate engine directory by checking for the platform-specific editor binary.
    /// </summary>
    public static bool IsValidEngineRoot(string? path)
    {
        if (string.IsNullOrEmpty(path) || !Directory.Exists(path))
            return false;

        // UE5 first
        if (File.Exists(GetEditorBinaryPath(path, isUE5: true)))
            return true;

        // Fall back to UE4
        if (File.Exists(GetEditorBinaryPath(path, isUE5: false)))
            return true;

        return false;
    }

    /// <summary>
    /// Get the editor binary path for the current platform.
    /// </summary>
    public static string GetEditorBinaryPath(string enginePath, bool isUE5 = true)
    {
        var editorName = isUE5 ? "UnrealEditor" : "UE4Editor";

        if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
            return Path.Combine(enginePath, "Engine", "Binaries", "Win64", $"{editorName}.exe");

        if (RuntimeInformation.IsOSPlatform(OSPlatform.OSX))
            return Path.Combine(enginePath, "Engine", "Binaries", "Mac", $"{editorName}.app", "Contents", "MacOS", editorName);

        // Linux
        return Path.Combine(enginePath, "Engine", "Binaries", "Linux", editorName);
    }

    private static string ResolveRelativePath(string basePath, string relativePath)
    {
        if (Path.IsPathRooted(relativePath))
            return relativePath;
        return Path.GetFullPath(Path.Combine(basePath, relativePath));
    }

    private static string? GetUProjectDirectory(string repoPath, UProjectMeta meta)
    {
        // Try to find the .uproject file's directory
        var uprojectFiles = Directory.GetFiles(repoPath, "*.uproject", SearchOption.TopDirectoryOnly);
        return uprojectFiles.Length > 0
            ? Path.GetDirectoryName(uprojectFiles[0])
            : null;
    }

    private static IEnumerable<string> GetKnownInstallPaths(string? versionStr)
    {
        if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
        {
            var programFiles = Environment.GetFolderPath(Environment.SpecialFolder.ProgramFiles);
            var epicDir = Path.Combine(programFiles, "Epic Games");

            if (Directory.Exists(epicDir))
            {
                foreach (var dir in Directory.GetDirectories(epicDir, "UE_*"))
                {
                    if (versionStr == null || Path.GetFileName(dir).Contains(versionStr))
                        yield return dir;
                }
            }

            var localAppData = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
            yield return Path.Combine(localAppData, "EpicGamesLauncher", "Engine");
        }
        else if (RuntimeInformation.IsOSPlatform(OSPlatform.OSX))
        {
            var home = Environment.GetFolderPath(Environment.SpecialFolder.UserProfile);
            yield return Path.Combine(home, "Library", "Application Support", "Epic", "UnrealEngine");
            yield return Path.Combine("/Users", "Shared", "Epic Games");
        }
        else // Linux
        {
            var home = Environment.GetFolderPath(Environment.SpecialFolder.UserProfile);
            foreach (var dir in Directory.GetDirectories(home, "EpicGames/UE_*"))
                yield return dir;
            yield return Path.Combine("/opt", "EpicGames");
        }
    }

    private static bool TryRegistryLookup(string? guid, out string? path)
    {
        path = null;
        if (!RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
            return false;

        // Registry scanning is best-effort — we try standard keys
        var registryKeys = new[]
        {
            @"SOFTWARE\EpicGames\Unreal Engine",
        };

        var hives = new[]
        {
            Microsoft.Win32.Registry.CurrentUser,
            Microsoft.Win32.Registry.LocalMachine
        };

        foreach (var hive in hives)
        {
            foreach (var keyPath in registryKeys)
            {
                try
                {
                    using var key = hive.OpenSubKey(keyPath);
                    if (key == null) continue;

                    if (guid != null)
                    {
                        using var subKey = key.OpenSubKey(guid);
                        if (subKey != null)
                        {
                            path = subKey.GetValue("InstalledDirectory") as string;
                            if (!string.IsNullOrEmpty(path) && IsValidEngineRoot(path))
                                return true;
                        }
                    }
                    else
                    {
                        // Scan all sub-keys for any installed versions
                        foreach (var subKeyName in key.GetSubKeyNames())
                        {
                            using var subKey = key.OpenSubKey(subKeyName);
                            if (subKey == null) continue;

                            path = subKey.GetValue("InstalledDirectory") as string;
                            if (!string.IsNullOrEmpty(path) && IsValidEngineRoot(path))
                                return true;
                        }
                    }
                }
                catch
                {
                    // Registry access can fail due to permissions — continue
                    continue;
                }
            }
        }

        return false;
    }
}

using System;
using System.IO;
using System.Text.Json;

using SourceGit.Models;

namespace SourceGit.Services;

/// <summary>
/// Detects engine version and build type from Engine/Build/Build.version.
/// This service does synchronous file I/O — callers should run on a background thread
/// (the VM already does via Task.Run in UnrealSyncTabViewModel).
/// </summary>
public static class EngineInfoService
{
    /// <summary>
    /// Read Engine/Build/Build.version JSON to determine engine version.
    /// Returns EngineInfo with Version="Unknown" if the file doesn't exist or parsing fails.
    /// </summary>
    public static EngineInfo Detect(string enginePath)
    {
        var versionPath = Path.Combine(enginePath, "Engine", "Build", "Build.version");
        if (!File.Exists(versionPath))
            return new EngineInfo { Version = "Unknown", BuildType = "Unknown" };

        try
        {
            var json = File.ReadAllText(versionPath);
            var buildVersion = JsonSerializer.Deserialize(json, UnrealSyncJsonContext.Default.BuildVersion);
            if (buildVersion == null)
                return new EngineInfo { Version = "Unknown", BuildType = "Unknown" };

            var isSourceBuild = !File.Exists(Path.Combine(enginePath, ".licensee"));
            var isLauncherBuild = buildVersion.IsLicenseeVersion == 1;

            return new EngineInfo
            {
                MajorVersion = buildVersion.MajorVersion,
                MinorVersion = buildVersion.MinorVersion,
                PatchVersion = buildVersion.PatchVersion,
                Changelist = buildVersion.Changelist,
                Version = $"{buildVersion.MajorVersion}.{buildVersion.MinorVersion}.{buildVersion.PatchVersion}",
                BuildType = isLauncherBuild ? "Launcher" : (isSourceBuild ? "Source" : "Custom"),
                IsSourceBuild = isSourceBuild
            };
        }
        catch (Exception)
        {
            return new EngineInfo { Version = "Unknown", BuildType = "Unknown" };
        }
    }
}

using System;
using System.Diagnostics;
using System.Threading;
using System.Threading.Tasks;

using SourceGit.Models;

namespace SourceGit.Services;

/// <summary>
/// Delegates git operations to SourceGit's Commands infrastructure to avoid
/// index.lock conflicts. Fixes RC-9.
/// </summary>
public class GitSyncService
{
    public enum SyncStatus { Success, Conflict, Failed }

    public record SyncResult(
        SyncStatus Status,
        string Message,
        string? CommitSha = null,
        TimeSpan? Duration = null
    );

    private readonly string _repoPath;

    public GitSyncService(string repoPath)
    {
        _repoPath = repoPath;
    }

    /// <summary>
    /// Sync to latest on current branch using git pull --rebase.
    /// Checks for dirty working tree first.
    /// </summary>
    public async Task<SyncResult> SyncToLatestAsync(
        string branch, IProgress<string>? log, CancellationToken ct)
    {
        var sw = Stopwatch.StartNew();

        // Check for dirty working tree
        if (await HasDirtyWorkingTreeAsync(ct))
        {
            return new SyncResult(SyncStatus.Conflict,
                "Working tree is dirty. Commit or stash changes before syncing.");
        }

        // Run git pull --rebase via SourceGit's Commands
        try
        {
            // Use SourceGit's command runner pattern
            var result = await RunGitCommandAsync(
                $"pull --rebase origin {branch}", log, ct);

            sw.Stop();

            if (result.ExitCode == 0)
            {
                var commitSha = await GetCurrentCommitAsync(ct);
                return new SyncResult(SyncStatus.Success,
                    "Sync completed successfully.", commitSha, sw.Elapsed);
            }

            return new SyncResult(SyncStatus.Failed,
                $"Sync failed (exit code {result.ExitCode}): {result.StdErr}", null, sw.Elapsed);
        }
        catch (OperationCanceledException)
        {
            sw.Stop();
            return new SyncResult(SyncStatus.Failed, "Sync cancelled.", null, sw.Elapsed);
        }
        catch (Exception ex)
        {
            sw.Stop();
            Native.OS.LogException(ex);
            return new SyncResult(SyncStatus.Failed, $"Sync error: {ex.Message}", null, sw.Elapsed);
        }
    }

    /// <summary>
    /// Checkout a specific commit. Refuses if working tree is dirty.
    /// </summary>
    public async Task<SyncResult> SyncToCommitAsync(
        string commitSha, IProgress<string>? log, CancellationToken ct)
    {
        var sw = Stopwatch.StartNew();

        if (await HasDirtyWorkingTreeAsync(ct))
        {
            return new SyncResult(SyncStatus.Conflict,
                "Working tree is dirty. Commit or stash changes before syncing.");
        }

        try
        {
            var result = await RunGitCommandAsync(
                $"checkout {commitSha}", log, ct);

            sw.Stop();

            if (result.ExitCode == 0)
            {
                return new SyncResult(SyncStatus.Success,
                    $"Checked out commit {commitSha[..Math.Min(7, commitSha.Length)]}.", commitSha, sw.Elapsed);
            }

            return new SyncResult(SyncStatus.Failed,
                $"Checkout failed (exit code {result.ExitCode}): {result.StdErr}", null, sw.Elapsed);
        }
        catch (OperationCanceledException)
        {
            sw.Stop();
            return new SyncResult(SyncStatus.Failed, "Checkout cancelled.", null, sw.Elapsed);
        }
        catch (Exception ex)
        {
            sw.Stop();
            Native.OS.LogException(ex);
            return new SyncResult(SyncStatus.Failed, $"Checkout error: {ex.Message}", null, sw.Elapsed);
        }
    }

    public async Task<string> GetCurrentBranchAsync(CancellationToken ct)
    {
        var result = await RunGitCommandAsync("rev-parse --abbrev-ref HEAD", null, ct);
        return result.ExitCode == 0 ? result.StdOut.Trim() : "unknown";
    }

    public async Task<string> GetCurrentCommitAsync(CancellationToken ct)
    {
        var result = await RunGitCommandAsync("rev-parse HEAD", null, ct);
        return result.ExitCode == 0 ? result.StdOut.Trim() : string.Empty;
    }

    private async Task<bool> HasDirtyWorkingTreeAsync(CancellationToken ct)
    {
        var result = await RunGitCommandAsync("status --porcelain", null, ct);
        return result.ExitCode == 0 && !string.IsNullOrWhiteSpace(result.StdOut);
    }

    private async Task<(int ExitCode, string StdOut, string StdErr)> RunGitCommandAsync(
        string arguments, IProgress<string>? log, CancellationToken ct)
    {
        var psi = new ProcessStartInfo
        {
            FileName = "git",
            Arguments = arguments,
            WorkingDirectory = _repoPath,
            UseShellExecute = false,
            CreateNoWindow = true,
            RedirectStandardOutput = true,
            RedirectStandardError = true
        };

        using var process = new Process { StartInfo = psi };
        process.Start();

        var stdoutTask = process.StandardOutput.ReadToEndAsync(ct);
        var stderrTask = process.StandardError.ReadToEndAsync(ct);

        await process.WaitForExitAsync(ct);

        var stdout = await stdoutTask;
        var stderr = await stderrTask;

        log?.Report(stdout);
        if (!string.IsNullOrWhiteSpace(stderr))
            log?.Report(stderr);

        return (process.ExitCode, stdout, stderr);
    }
}

using System;
using System.IO;
using System.Text;

using Avalonia.Collections;
using Avalonia.Threading;

using CommunityToolkit.Mvvm.ComponentModel;

namespace SourceGit.ViewModels
{
    public class Launcher : ObservableObject
    {
        public string Title
        {
            get => _title;
            private set => SetProperty(ref _title, value);
        }

        public AvaloniaList<LauncherPage> Pages
        {
            get;
            private set;
        }

        public Workspace ActiveWorkspace
        {
            get => _activeWorkspace;
            private set => SetProperty(ref _activeWorkspace, value);
        }

        public LauncherPage ActivePage
        {
            get => _activePage;
            set
            {
                if (SetProperty(ref _activePage, value))
                    PostActivePageChanged();
            }
        }

        public ICommandPalette CommandPalette
        {
            get => _commandPalette;
            set => SetProperty(ref _commandPalette, value);
        }

        public Launcher(string startupRepo)
        {
            Models.Notification.Raised += DispatchNotification;
            _ignoreIndexChange = true;

            Pages = new AvaloniaList<LauncherPage>();
            AddNewTab();

            var pref = Preferences.Instance;
            ActiveWorkspace = pref.GetActiveWorkspace();

            var repos = ActiveWorkspace.Repositories.ToArray();
            foreach (var repo in repos)
            {
                var node = pref.FindNode(repo) ??
                    new RepositoryNode
                    {
                        Id = repo,
                        Name = Path.GetFileName(repo),
                        Bookmark = 0,
                        IsRepository = true,
                    };

                OpenRepositoryInTab(node, null);
            }

            _ignoreIndexChange = false;

            if (TryOpenRepositoryFromPath(startupRepo))
                return;

            if (!string.IsNullOrEmpty(startupRepo))
            {
                var test = new Commands.QueryRepositoryRootPath(startupRepo).GetResult();
                if (test.IsSuccess && !string.IsNullOrEmpty(test.StdOut))
                {
                    var node = pref.FindOrAddNodeByRepositoryPath(test.StdOut.Trim(), null, false);
                    Welcome.Instance.Refresh();

                    OpenRepositoryInTab(node, null);
                    return;
                }
            }

            var activeIdx = ActiveWorkspace.ActiveIdx;
            if (activeIdx > 0 && activeIdx < Pages.Count)
            {
                ActivePage = Pages[activeIdx];
                return;
            }

            ActivePage = Pages[0];
            PostActivePageChanged();
        }

        public bool TryOpenRepositoryFromPath(string repo)
        {
            if (!string.IsNullOrEmpty(repo) && Directory.Exists(repo))
            {
                var test = new Commands.QueryRepositoryRootPath(repo).GetResult();
                if (test.IsSuccess && !string.IsNullOrEmpty(test.StdOut))
                {
                    var node = Preferences.Instance.FindOrAddNodeByRepositoryPath(test.StdOut.Trim(), null, false);
                    Welcome.Instance.Refresh();
                    OpenRepositoryInTab(node, null);
                    return true;
                }
            }

            return false;
        }

        public void CloseAll()
        {
            _ignoreIndexChange = true;

            foreach (var one in Pages)
                CloseRepositoryInTab(one, false);

            _ignoreIndexChange = false;
        }

        public void SwitchWorkspace(Workspace to)
        {
            if (to == null || to.IsActive)
                return;

            _ignoreIndexChange = true;

            var pref = Preferences.Instance;
            foreach (var w in pref.Workspaces)
                w.IsActive = false;

            ActiveWorkspace = to;
            to.IsActive = true;

            foreach (var one in Pages)
                CloseRepositoryInTab(one, false);

            Pages.Clear();
            AddNewTab();

            var repos = to.Repositories.ToArray();
            foreach (var repo in repos)
            {
                var node = pref.FindNode(repo) ??
                    new RepositoryNode
                    {
                        Id = repo,
                        Name = Path.GetFileName(repo),
                        Bookmark = 0,
                        IsRepository = true,
                    };

                OpenRepositoryInTab(node, null);
            }

            var activeIdx = to.ActiveIdx;
            if (activeIdx >= 0 && activeIdx < Pages.Count)
                ActivePage = Pages[activeIdx];
            else
                ActivePage = Pages[0];

            _ignoreIndexChange = false;
            PostActivePageChanged();
            Preferences.Instance.Save();
            GC.Collect();
        }

        public void AddNewTab()
        {
            var page = new LauncherPage();
            Pages.Add(page);
            ActivePage = page;
        }

        public void MoveTab(LauncherPage from, LauncherPage to)
        {
            _ignoreIndexChange = true;

            var fromIdx = Pages.IndexOf(from);
            var toIdx = Pages.IndexOf(to);
            Pages.Move(fromIdx, toIdx);

            _activeWorkspace.Repositories.Clear();
            foreach (var p in Pages)
            {
                if (p.Data is Repository r)
                    _activeWorkspace.Repositories.Add(r.FullPath);
            }

            _ignoreIndexChange = false;
            ActivePage = from;
        }

        public void GotoNextTab()
        {
            if (Pages.Count == 1)
                return;

            var activeIdx = Pages.IndexOf(_activePage);
            var nextIdx = (activeIdx + 1) % Pages.Count;
            ActivePage = Pages[nextIdx];
        }

        public void GotoPrevTab()
        {
            if (Pages.Count == 1)
                return;

            var activeIdx = Pages.IndexOf(_activePage);
            var prevIdx = activeIdx == 0 ? Pages.Count - 1 : activeIdx - 1;
            ActivePage = Pages[prevIdx];
        }

        public void CloseTab(LauncherPage page)
        {
            if (Pages.Count == 1)
            {
                var last = Pages[0];
                if (last.Data is Repository repo)
                {
                    _activeWorkspace.Repositories.Clear();
                    _activeWorkspace.ActiveIdx = 0;

                    repo.Close();

                    Welcome.Instance.ClearSearchFilter();
                    last.Node = new RepositoryNode() { Id = Guid.NewGuid().ToString() };
                    last.Data = Welcome.Instance;
                    last.Popup?.Cleanup();
                    last.Popup = null;

                    PostActivePageChanged();
                    GC.Collect();
                }
                else
                {
                    App.Quit(0);
                }

                return;
            }

            page ??= _activePage;

            var removeIdx = Pages.IndexOf(page);
            var activeIdx = Pages.IndexOf(_activePage);
            if (removeIdx == activeIdx)
                ActivePage = Pages[removeIdx > 0 ? removeIdx - 1 : removeIdx + 1];

            CloseRepositoryInTab(page);
            Pages.RemoveAt(removeIdx);
            GC.Collect();
        }

        public void CloseOtherTabs()
        {
            if (Pages.Count == 1)
                return;

            _ignoreIndexChange = true;

            var id = ActivePage.Node.Id;
            foreach (var one in Pages)
            {
                if (one.Node.Id != id)
                    CloseRepositoryInTab(one);
            }

            Pages = new AvaloniaList<LauncherPage> { ActivePage };
            OnPropertyChanged(nameof(Pages));

            _activeWorkspace.ActiveIdx = 0;
            _ignoreIndexChange = false;
            GC.Collect();
        }

        public void CloseRightTabs()
        {
            _ignoreIndexChange = true;

            var endIdx = Pages.IndexOf(ActivePage);
            for (var i = Pages.Count - 1; i > endIdx; i--)
            {
                CloseRepositoryInTab(Pages[i]);
                Pages.Remove(Pages[i]);
            }

            _ignoreIndexChange = false;
            GC.Collect();
        }

        public void OpenRepositoryInTab(RepositoryNode node, LauncherPage page)
        {
            foreach (var one in Pages)
            {
                if (one.Node.Id == node.Id)
                {
                    ActivePage = one;
                    return;
                }
            }

            if (!Directory.Exists(node.Id))
            {
                ActivePage.Notifications.Add(new Models.Notification
                {
                    Group = node.Id,
                    Message = "Repository does NOT exist any more. Please remove it.",
                    IsError = true,
                });
                return;
            }

            var isBare = new Commands.IsBareRepository(node.Id).GetResult();
            var gitDir = isBare ? node.Id : GetRepositoryGitDir(node.Id);
            if (string.IsNullOrEmpty(gitDir))
            {
                ActivePage.Notifications.Add(new Models.Notification
                {
                    Group = node.Id,
                    Message = "Given path is not a valid git repository!",
                    IsError = true,
                });
                return;
            }

            var repo = new Repository(isBare, node.Id, gitDir);
            repo.Open();

            if (page == null)
            {
                if (_activePage == null || _activePage.Node.IsRepository)
                {
                    page = new LauncherPage(node, repo);
                    Pages.Add(page);
                }
                else
                {
                    page = _activePage;
                    page.Node = node;
                    page.Data = repo;
                }
            }
            else
            {
                page.Node = node;
                page.Data = repo;
            }

            _activeWorkspace.Repositories.Clear();
            foreach (var p in Pages)
            {
                if (p.Data is Repository r)
                    _activeWorkspace.Repositories.Add(r.FullPath);
            }

            if (_activePage == page)
                PostActivePageChanged();
            else
                ActivePage = page;
        }

        private void DispatchNotification(Models.Notification notification)
        {
            if (!Dispatcher.UIThread.CheckAccess())
            {
                Dispatcher.UIThread.Invoke(() => DispatchNotification(notification));
                return;
            }

            if (string.IsNullOrEmpty(notification.Group))
            {
                _activePage?.Notifications.Add(notification);
                return;
            }

            foreach (var page in Pages)
            {
                var id = page.Node.Id.Replace('\\', '/').TrimEnd('/');
                if (id.Equals(notification.Group, StringComparison.OrdinalIgnoreCase))
                {
                    page.Notifications.Add(notification);
                    return;
                }
            }

            _activePage?.Notifications.Add(notification);
        }

        private string GetRepositoryGitDir(string repo)
        {
            var fullpath = Path.Combine(repo, ".git");
            if (Directory.Exists(fullpath))
            {
                if (Directory.Exists(Path.Combine(fullpath, "refs")) &&
                    Directory.Exists(Path.Combine(fullpath, "objects")) &&
                    File.Exists(Path.Combine(fullpath, "HEAD")))
                    return fullpath;

                return null;
            }

            if (File.Exists(fullpath))
            {
                var redirect = File.ReadAllText(fullpath).Trim();
                if (redirect.StartsWith("gitdir: ", StringComparison.Ordinal))
                    redirect = redirect.Substring(8);

                if (!Path.IsPathRooted(redirect))
                    redirect = Path.GetFullPath(Path.Combine(repo, redirect));

                if (Directory.Exists(redirect))
                    return redirect;

                return null;
            }

            return new Commands.QueryGitDir(repo).GetResult();
        }

        private void CloseRepositoryInTab(LauncherPage page, bool removeFromWorkspace = true)
        {
            if (page.Data is Repository repo)
            {
                if (removeFromWorkspace)
                    _activeWorkspace.Repositories.Remove(repo.FullPath);

                repo.Close();
            }

            page.Popup?.Cleanup();
            page.Popup = null;
            page.Data = null;
            page.Dispose();
        }

        private void PostActivePageChanged()
        {
            if (_ignoreIndexChange)
                return;

            if (_activePage is { Data: Repository repo })
                _activeWorkspace.ActiveIdx = _activeWorkspace.Repositories.IndexOf(repo.FullPath);

            var builder = new StringBuilder(512);
            builder.Append(string.IsNullOrEmpty(_activePage.Node.Name) ? "Repositories" : _activePage.Node.Name);

            var workspaces = Preferences.Instance.Workspaces;
            if (workspaces.Count == 0 || workspaces.Count > 1 || workspaces[0] != _activeWorkspace)
                builder.Append(" - ").Append(_activeWorkspace.Name);

            Title = builder.ToString();
            CommandPalette = null;
        }

        private Workspace _activeWorkspace;
        private LauncherPage _activePage;
        private bool _ignoreIndexChange;
        private string _title = string.Empty;
        private ICommandPalette _commandPalette;
    }
}

using System;
using System.Linq;
using System.Threading.Tasks;

using Avalonia.Collections;
using Avalonia.Threading;

using CommunityToolkit.Mvvm.ComponentModel;

using SourceGit.Models;
using SourceGit.ViewModels.Tabs;

namespace SourceGit.ViewModels
{
    public class LauncherPage : ObservableObject
    {
        public RepositoryNode Node
        {
            get => _node;
            set => SetProperty(ref _node, value);
        }

        public object Data
        {
            get => _data;
            set => SetProperty(ref _data, value);
        }

        public Models.DirtyState DirtyState
        {
            get => _dirtyState;
            private set => SetProperty(ref _dirtyState, value);
        }

        public Popup Popup
        {
            get => _popup;
            set => SetProperty(ref _popup, value);
        }

        public AvaloniaList<Models.Notification> Notifications
        {
            get;
            set;
        } = new AvaloniaList<Models.Notification>();

        public AvaloniaList<RepositoryTabDescriptor> Tabs { get; } = new();

        public RepositoryTabDescriptor SelectedTab
        {
            get => _selectedTab;
            set
            {
                var previous = _selectedTab;
                if (SetProperty(ref _selectedTab, value))
                {
                    OnPropertyChanged(nameof(ToolbarContent));
                    OnPropertyChanged(nameof(BodyContent));

                    if (previous != null)
                        previous.NotifyDeactivated();

                    if (value != null)
                    {
                        value.NotifyActivated();
                        PersistActiveTabId(value.TabId);
                    }
                }
            }
        }

        /// <summary>
        /// Toolbar content: uses SelectedTab's toolbar if available, otherwise falls back to Data (Welcome page).
        /// </summary>
        public object ToolbarContent => _selectedTab?.ToolbarContent ?? _data;

        /// <summary>
        /// Body content: uses SelectedTab's body if available, otherwise falls back to Data (Welcome page).
        /// </summary>
        public object BodyContent => _selectedTab?.BodyContent ?? _data;

        public bool IsTabBarVisible => Tabs.Count > 1;

        public LauncherPage()
        {
            _node = new RepositoryNode() { Id = Guid.NewGuid().ToString() };
            _data = Welcome.Instance;

            // New welcome page will clear the search filter before.
            Welcome.Instance.ClearSearchFilter();

            Tabs.CollectionChanged += (_, _) => OnPropertyChanged(nameof(IsTabBarVisible));
        }

        public LauncherPage(RepositoryNode node, Repository repo)
        {
            _node = node;
            _data = repo;

            Tabs.CollectionChanged += (_, _) => OnPropertyChanged(nameof(IsTabBarVisible));

            // Subscribe to plugin state changes for live activation/deactivation
            PluginRegistry.Instance.PluginStateChanged += OnPluginStateChanged;

            RegisterBuiltInTabs();
            RestoreActiveTab();
        }

        public void AddPluginTab(IRepositoryTab tab)
        {
            if (_isDisposed)
                throw new ObjectDisposedException(nameof(LauncherPage));

            if (!Dispatcher.UIThread.CheckAccess())
            {
                Dispatcher.UIThread.Post(() => AddPluginTab(tab));
                return;
            }

            // Duplicate TabId guard
            if (Tabs.Any(t => t.TabId == tab.TabId))
            {
                Native.OS.LogException(new InvalidOperationException($"Duplicate tab ID '{tab.TabId}' — ignoring"));
                return;
            }

            RepositoryTabDescriptor descriptor;
            try
            {
                // Test that content properties don't throw
                _ = tab.ToolbarContent;
                _ = tab.BodyContent;
                descriptor = new RepositoryTabDescriptor(tab);
            }
            catch (Exception ex)
            {
                Native.OS.LogException(new InvalidOperationException($"Plugin tab '{tab.TabId}' failed to initialize: {ex.Message}"));
                descriptor = CreateErrorTabDescriptor(tab.TabId, tab.Title, ex);
            }

            // Insert at correct position based on SortOrder
            var insertIndex = 0;
            for (int i = 0; i < Tabs.Count; i++)
            {
                if (Tabs[i].SortOrder <= descriptor.SortOrder)
                    insertIndex = i + 1;
                else
                    break;
            }
            Tabs.Insert(insertIndex, descriptor);

            descriptor.RequestClose += OnTabRequestClose;
        }

        public void RemovePluginTab(IRepositoryTab tab)
        {
            if (!Dispatcher.UIThread.CheckAccess())
            {
                Dispatcher.UIThread.Post(() => RemovePluginTab(tab));
                return;
            }

            var descriptor = Tabs.FirstOrDefault(t => t.Tab == tab);
            if (descriptor == null)
                return;
            if (!descriptor.IsClosable)
                return;

            descriptor.RequestClose -= OnTabRequestClose;

            // If removing the selected tab, switch to the previous one
            if (SelectedTab == descriptor)
            {
                var fallbackIndex = Math.Max(0, Tabs.IndexOf(descriptor) - 1);
                SelectedTab = Tabs[fallbackIndex];
            }

            Tabs.Remove(descriptor);
            descriptor.Dispose();
        }

        public void SelectTab(int index)
        {
            if (index >= 0 && index < Tabs.Count)
                SelectedTab = Tabs[index];
        }

        public void SelectTab(string tabId)
        {
            var tab = Tabs.FirstOrDefault(t => t.TabId == tabId);
            if (tab != null)
                SelectedTab = tab;
        }

        public void SelectNextTab(bool reverse = false)
        {
            if (Tabs.Count <= 1)
                return;

            var currentIndex = Tabs.IndexOf(SelectedTab);
            if (currentIndex < 0)
                return;

            int nextIndex;
            if (reverse)
            {
                nextIndex = currentIndex - 1;
                if (nextIndex < 0)
                    nextIndex = Tabs.Count - 1;
            }
            else
            {
                nextIndex = currentIndex + 1;
                if (nextIndex >= Tabs.Count)
                    nextIndex = 0;
            }

            SelectedTab = Tabs[nextIndex];
        }

        public void ClearNotifications()
        {
            Notifications.Clear();
        }

        public void ChangeDirtyState(Models.DirtyState flag, bool remove)
        {
            var state = _dirtyState;
            if (remove)
            {
                if (state.HasFlag(flag))
                    state -= flag;
            }
            else
            {
                state |= flag;
            }

            DirtyState = state;
        }

        public bool CanCreatePopup()
        {
            return _popup is not { InProgress: true };
        }

        public async Task ProcessPopupAsync()
        {
            if (_popup is { InProgress: false } dump)
            {
                if (!dump.Check())
                    return;

                dump.InProgress = true;

                try
                {
                    var finished = await dump.Sure();
                    if (finished)
                    {
                        dump.Cleanup();
                        Popup = null;
                    }
                }
                catch (Exception e)
                {
                    Native.OS.LogException(e);
                }

                dump.InProgress = false;
            }
        }

        public void CancelPopup()
        {
            if (_popup == null || _popup.InProgress)
                return;

            _popup?.Cleanup();
            Popup = null;
        }

        internal void Dispose()
        {
            _isDisposed = true;

            // Unsubscribe from plugin state changes
            PluginRegistry.Instance.PluginStateChanged -= OnPluginStateChanged;

            foreach (var descriptor in Tabs)
                descriptor.Dispose();
            Tabs.Clear();
        }

        private void OnPluginStateChanged(string pluginId, string repositoryPath)
        {
            // Must run on UI thread
            if (!Dispatcher.UIThread.CheckAccess())
            {
                Dispatcher.UIThread.Post(() => OnPluginStateChanged(pluginId, repositoryPath));
                return;
            }

            if (_isDisposed || !(_data is Repository repo))
                return;

            // Find the manifest for this plugin
            var manifest = PluginRegistry.Instance.AllManifests.FirstOrDefault(m => m.PluginId == pluginId);
            if (manifest == null)
                return;

            var uiStates = repo.UIStates;
            var isEnabled = PluginRegistry.Instance.IsEnabledForRepository(pluginId, uiStates);

            // Check if the plugin's tabs are currently present
            var pluginTabIds = PluginRegistry.Instance.GetTabIdsForPlugin(pluginId);
            bool hasPluginTabs = false;
            foreach (var tab in Tabs)
            {
                if (pluginTabIds.Contains(tab.TabId))
                {
                    hasPluginTabs = true;
                    break;
                }
            }

            if (isEnabled && !hasPluginTabs)
            {
                // Plugin was enabled but not present — activate it
                PluginActivator.ActivatePlugin(manifest, this, _node);
            }
            else if (!isEnabled && hasPluginTabs)
            {
                // Plugin was disabled but still present — deactivate it
                PluginActivator.DeactivatePlugin(manifest, this);
            }
        }

        private void RegisterBuiltInTabs()
        {
            var repo = _data as Repository;
            if (repo == null)
                return;

            var repoTab = new RepositoryTab(repo, _node);
            Tabs.Add(new RepositoryTabDescriptor(repoTab));

            // Activate enabled plugins for this repository
            PluginActivator.ActivateEnabledPlugins(this, _node, repo.UIStates);

            SelectedTab = Tabs[0];
        }

        private void RestoreActiveTab()
        {
            if (_data is Repository repo)
            {
                var savedTabId = repo.UIStates.ActiveTabId;
                if (!string.IsNullOrEmpty(savedTabId))
                {
                    var tab = Tabs.FirstOrDefault(t => t.TabId == savedTabId);
                    if (tab != null)
                        SelectedTab = tab;
                }
            }
            // If savedTabId invalid or tab not found, SelectedTab stays at Tabs[0] (Repository)
        }

        private void PersistActiveTabId(string tabId)
        {
            if (_data is Repository repo)
                repo.UIStates.ActiveTabId = tabId;
        }

        private void OnTabRequestClose(object sender, EventArgs e)
        {
            if (sender is RepositoryTabDescriptor descriptor)
                RemovePluginTab(descriptor.Tab);
        }

        private RepositoryTabDescriptor CreateErrorTabDescriptor(string tabId, string title, Exception error)
        {
            var errorTab = new ErrorTab(tabId, title, error);
            return new RepositoryTabDescriptor(errorTab);
        }

        private RepositoryNode _node = null;
        private object _data = null;
        private Models.DirtyState _dirtyState = Models.DirtyState.None;
        private Popup _popup = null;
        private RepositoryTabDescriptor _selectedTab = null;
        private bool _isDisposed = false;
    }
}

using System.Collections.Generic;
using System.Linq;

using Avalonia.Collections;
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;

using SourceGit.Models;

namespace SourceGit.ViewModels
{
    public class PerRepoPluginDialogViewModel : ObservableObject
    {
        public enum OverrideState
        {
            Inherit,      // Use global default
            ForceEnable,  // Override to enabled
            ForceDisable  // Override to disabled
        }

        public class PluginOverrideRow : ObservableObject
        {
            public IPluginManifest Manifest { get; init; }
            private RepositoryUIStates _uiStates;

            public string PluginId => Manifest.PluginId;
            public string DisplayName => Manifest.DisplayName;
            public string Version => Manifest.Version;
            public string Author => Manifest.Author;
            public string Description => Manifest.Description;

            /// <summary>Whether this plugin is enabled globally (inherited default)</summary>
            public bool IsGlobalDefaultEnabled => PluginRegistry.Instance.IsEnabledGlobally(PluginId);

            /// <summary>Current override state for this plugin in this repository</summary>
            public OverrideState State
            {
                get
                {
                    var overrideVal = PluginRegistry.Instance.GetPerRepositoryOverride(PluginId, _uiStates);
                    if (overrideVal == true) return OverrideState.ForceEnable;
                    if (overrideVal == false) return OverrideState.ForceDisable;
                    return OverrideState.Inherit;
                }
                set
                {
                    switch (value)
                    {
                        case OverrideState.Inherit:
                            PluginRegistry.Instance.ResetForRepository(PluginId, _uiStates);
                            break;
                        case OverrideState.ForceEnable:
                            PluginRegistry.Instance.SetEnabledForRepository(PluginId, _uiStates, true);
                            break;
                        case OverrideState.ForceDisable:
                            PluginRegistry.Instance.SetEnabledForRepository(PluginId, _uiStates, false);
                            break;
                    }
                    OnPropertyChanged(nameof(State));
                    OnPropertyChanged(nameof(IsEnabledForRepo));
                    OnPropertyChanged(nameof(StateDisplayText));
                    OnPropertyChanged(nameof(StateIndex));
                }
            }

            /// <summary>Whether this plugin is currently enabled for this repo (effective value)</summary>
            public bool IsEnabledForRepo => PluginRegistry.Instance.IsEnabledForRepository(PluginId, _uiStates);

            /// <summary>Display text for the override state</summary>
            public string StateDisplayText => State switch
            {
                OverrideState.Inherit => IsGlobalDefaultEnabled ? "Inherit (Enabled)" : "Inherit (Disabled)",
                OverrideState.ForceEnable => "Enabled",
                OverrideState.ForceDisable => "Disabled",
                _ => "Inherit"
            };

            /// <summary>Index-based binding for ComboBox (0=Inherit, 1=ForceEnable, 2=ForceDisable)</summary>
            public int StateIndex
            {
                get => (int)State;
                set => State = (OverrideState)value;
            }

            public PluginOverrideRow(IPluginManifest manifest, RepositoryUIStates uiStates)
            {
                Manifest = manifest;
                _uiStates = uiStates;
            }
        }

        public AvaloniaList<PluginOverrideRow> Plugins { get; } = new();

        public string RepositoryName { get; }

        public PerRepoPluginDialogViewModel(string repoPath, string repoName, RepositoryUIStates uiStates)
        {
            RepositoryName = repoName;

            foreach (var manifest in PluginRegistry.Instance.AllManifests)
            {
                Plugins.Add(new PluginOverrideRow(manifest, uiStates));
            }
        }

        public void ResetAllToDefaults()
        {
            foreach (var plugin in Plugins)
            {
                if (plugin.State != OverrideState.Inherit)
                    plugin.State = OverrideState.Inherit;
            }
        }
    }
}

using System;
using System.Collections.Generic;
using System.IO;

using SourceGit.Models;
using SourceGit.ViewModels;
using SourceGit.ViewModels.Tabs;

namespace SourceGit.Models
{
    /// <summary>
    /// Creates tab instances from enabled plugins for a specific repository.
    /// Called by LauncherPage after RegisterBuiltInTabs().
    /// </summary>
    public static class PluginActivator
    {
        /// <summary>
        /// Creates and adds tabs for all enabled plugins for the given repository.
        /// Called during LauncherPage initialization.
        /// </summary>
        public static void ActivateEnabledPlugins(LauncherPage page, ViewModels.RepositoryNode node, RepositoryUIStates uiStates)
        {
            foreach (var manifest in PluginRegistry.Instance.AllManifests)
            {
                if (!PluginRegistry.Instance.IsEnabledForRepository(manifest.PluginId, uiStates))
                    continue;

                ActivatePlugin(manifest, page, node);
            }
        }

        /// <summary>
        /// Activates a single plugin (tab creation and addition).
        /// </summary>
        public static void ActivatePlugin(IPluginManifest manifest, LauncherPage page, ViewModels.RepositoryNode node)
        {
            var repoPath = node.Id;
            var isFirstLoad = !PluginRegistry.Instance.HasBeenActivated(manifest.PluginId, repoPath);

            var context = new PluginContext
            {
                RepositoryPath = repoPath,
                RepositoryName = node.Name,
                GitDirectory = Path.Combine(repoPath, ".git"),
                IsFirstLoadForRepository = isFirstLoad,
            };

            IReadOnlyList<IRepositoryTab> tabs;
            try
            {
                tabs = manifest.CreateTabs(context);
            }
            catch (Exception ex)
            {
                Native.OS.LogException(new InvalidOperationException(
                    $"Plugin '{manifest.PluginId}' failed to create tabs: {ex.Message}", ex));

                var errorTab = new ErrorTab(
                    manifest.PluginId,
                    manifest.DisplayName,
                    new InvalidOperationException($"Plugin initialization failed: {ex.Message}", ex));
                page.AddPluginTab(errorTab);

                // Track the error tab as belonging to this plugin
                PluginRegistry.Instance.RegisterTabToPlugin(errorTab.TabId, manifest.PluginId);
                return;
            }

            if (tabs != null)
            {
                foreach (var tab in tabs)
                {
                    page.AddPluginTab(tab);
                    PluginRegistry.Instance.RegisterTabToPlugin(tab.TabId, manifest.PluginId);
                }
            }

            PluginRegistry.Instance.MarkActivated(manifest.PluginId, repoPath);
        }

        /// <summary>
        /// Deactivates a single plugin by removing its tabs from the page.
        /// </summary>
        public static void DeactivatePlugin(IPluginManifest manifest, LauncherPage page)
        {
            var tabIds = PluginRegistry.Instance.GetTabIdsForPlugin(manifest.PluginId);
            var tabsToRemove = new List<IRepositoryTab>();

            foreach (var descriptor in page.Tabs)
            {
                if (tabIds.Contains(descriptor.TabId))
                    tabsToRemove.Add(descriptor.Tab);
            }

            foreach (var tab in tabsToRemove)
            {
                PluginRegistry.Instance.UnregisterTabFromPlugin(tab.TabId, manifest.PluginId);
                page.RemovePluginTab(tab);
            }
        }
    }
}

using System.Collections.Generic;
using System.IO;
using System.Linq;

using Avalonia.Collections;
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;

using SourceGit.Models;

namespace SourceGit.ViewModels
{
    public class PluginSettingsViewModel : ObservableObject
    {
        /// <summary>
        /// Represents a single plugin row in the settings UI.
        /// </summary>
        public class PluginRow : ObservableObject
        {
            public IPluginManifest Manifest { get; init; }
            public string DllPath { get; init; }
            public bool IsLoaded { get; init; }
            public bool IsSkipped { get; init; }
            public string ErrorMessage { get; init; }

            public string PluginId => Manifest?.PluginId ?? "";
            public string DisplayName => Manifest?.DisplayName ?? Path.GetFileName(DllPath);
            public string Description => Manifest?.Description ?? "";
            public string Version => Manifest?.Version ?? "?";
            public string Author => Manifest?.Author ?? "";
            public bool IsGlobalByDefault => Manifest?.IsGlobalByDefault ?? false;
            public int DefaultSortOrder => Manifest?.DefaultSortOrder ?? 1000;

            /// <summary>Whether this plugin is enabled globally</summary>
            public bool IsGloballyEnabled
            {
                get => PluginRegistry.Instance.IsEnabledGlobally(PluginId);
                set
                {
                    PluginRegistry.Instance.SetGlobalDefault(PluginId, value);
                    OnPropertyChanged();
                }
            }

            /// <summary>Whether this row represents a failed load</summary>
            public bool HasError => !IsLoaded && !IsSkipped && !string.IsNullOrEmpty(ErrorMessage);

            /// <summary>Display string for default mode</summary>
            public string DefaultModeText => IsGlobalByDefault ? "Default: Global" : "Default: Per-Project";
        }

        public AvaloniaList<PluginRow> Plugins { get; } = new();

        public PluginSettingsViewModel()
        {
            LoadPlugins();
        }

        public void LoadPlugins()
        {
            Plugins.Clear();

            // Add built-in plugins
            foreach (var manifest in PluginRegistry.Instance.AllManifests)
            {
                Plugins.Add(new PluginRow
                {
                    Manifest = manifest,
                    DllPath = "(built-in)",
                    IsLoaded = true,
                });
            }

            // Add external plugin results (including failed/skipped)
            foreach (var result in PluginRegistry.Instance.DiscoveredPlugins)
            {
                Plugins.Add(new PluginRow
                {
                    Manifest = result.IsSuccess ? result.Manifest : null,
                    DllPath = result.DllPath,
                    IsLoaded = result.IsSuccess,
                    IsSkipped = result.IsSkipped,
                    ErrorMessage = result.ErrorMessage,
                });
            }
        }

        public void OpenPluginsFolder()
        {
            var pluginDir = Path.Combine(System.AppDomain.CurrentDomain.BaseDirectory, "plugins");
            if (!Directory.Exists(pluginDir))
                Directory.CreateDirectory(pluginDir);
            Native.OS.OpenInFileManager(pluginDir);
        }
    }
}

