namespace SourceGit.ViewModels.Tabs.UnrealSync;

public partial class StatusPanelViewModel : ObservableObject
{
    private readonly string _repoPath;
    private readonly string? _enginePath;
    private readonly GitSyncService _syncService;
    private BuildService? _buildService;
    private EditorLauncher? _editorLauncher;
    private CancellationTokenSource? _buildCts;

    [ObservableProperty]
    private string _statusText = "Ready";

    [ObservableProperty]
    private string _branchText = "unknown";

    [ObservableProperty]
    private string _commitText = "---";

    [ObservableProperty]
    private string _commitSubject = "";

    [ObservableProperty]
    private bool _isBusy;

    [ObservableProperty]
    private string _logOutput = string.Empty;

    public StatusPanelViewModel(string repoPath, string? enginePath)
    {
        _repoPath = repoPath;
        _enginePath = enginePath;
        _syncService = new GitSyncService(repoPath);

        if (enginePath != null)
        {
            _buildService = new BuildService(repoPath);
            _editorLauncher = new EditorLauncher(enginePath);
        }
    }

    public async Task RefreshAsync(CancellationToken ct)
    {
        try
        {
            BranchText = await _syncService.GetCurrentBranchAsync(ct);
            CommitText = await _syncService.GetCurrentCommitAsync(ct);
            StatusText = "Ready";
        }
        catch (Exception ex)
        {
            StatusText = $"Error: {ex.Message}";
        }
    }

    [RelayCommand]
    private async Task SyncAsync()
    {
        if (IsBusy) return;
        IsBusy = true;

        try
        {
            var cts = new CancellationTokenSource();
            var progress = new Progress<string>(AppendLog);
            var result = await _syncService.SyncToLatestAsync(
                BranchText, progress, cts.Token);

            AppendLog($"\n{result.Message}");

            if (result.Status == GitSyncService.SyncStatus.Success && result.CommitSha != null)
            {
                CommitText = result.CommitSha;
            }
        }
        catch (Exception ex)
        {
            AppendLog($"\nSync error: {ex.Message}");
        }
        finally
        {
            IsBusy = false;
        }
    }

    [RelayCommand]
    private async Task BuildAsync()
    {
        if (IsBusy || _buildService == null) return;
        IsBusy = true;

        try
        {
            _buildCts = new CancellationTokenSource();
            var progress = new Progress<string>(AppendLog);

            var config = ConfigService.LoadConfig(_repoPath);
            var steps = config.Engine?.BuildTargets;
            if (steps != null && steps.Count > 0)
            {
                var result = await _buildService.ExecuteAllAsync(steps, progress, _buildCts.Token);
                AppendLog($"\nBuild {result.Status}: {result.Message}");
            }
            else
            {
                AppendLog("\nNo build targets configured in .unrealsync.json");
            }
        }
        catch (Exception ex)
        {
            AppendLog($"\nBuild error: {ex.Message}");
        }
        finally
        {
            _buildCts = null;
            IsBusy = false;
        }
    }

    [RelayCommand]
    private void CancelBuild()
    {
        _buildCts?.Cancel();
    }

    [RelayCommand]
    private async Task LaunchEditorAsync()
    {
        if (_editorLauncher == null)
        {
            AppendLog("\nCannot launch editor: engine path not configured.");
            return;
        }

        try
        {
            var uprojectFiles = System.IO.Directory.GetFiles(_repoPath, "*.uproject");
            if (uprojectFiles.Length == 0)
            {
                AppendLog("\nNo .uproject file found.");
                return;
            }

            var config = ConfigService.LoadConfig(_repoPath);
            var args = config.Engine?.EditorArguments ?? "-log";

            await _editorLauncher.LaunchAsync(uprojectFiles[0], args);
            AppendLog("\nEditor launched.");
        }
        catch (Exception ex)
        {
            AppendLog($"\nLaunch error: {ex.Message}");
        }
    }

    private void AppendLog(string line)
    {
        Dispatcher.UIThread.Post(() =>
        {
            LogOutput += line + Environment.NewLine;
        });
    }
}

using System.Collections.Generic;

using UGSGit.Models;

namespace UGSGit.ViewModels.Tabs.UnrealSync;

public class UnrealSyncManifest : IPluginManifest
{
    public string PluginId => "sourcegit.unrealsync";
    public string DisplayName => "UnrealSync";
    public string Description => "Unreal Engine workspace sync, build, and launch workflow for Git";
    public string Version => "0.1.0";
    public string Author => "SourceGit";
    public bool IsGlobalByDefault => true;
    public int DefaultSortOrder => 100;

    public IReadOnlyList<IRepositoryTab> CreateTabs(PluginContext context)
    {
        var tab = new UnrealSyncTab(context.RepositoryPath);
        return new List<IRepositoryTab> { tab };
    }
}

using System.Security.Cryptography;
using System.Text;

using Avalonia;

using SourceGit.Models;

namespace SourceGit.ViewModels.Tabs.UnrealSync;

public class UnrealSyncTab : IRepositoryTab
{
    private readonly UnrealSyncTabViewModel _viewModel;
    private readonly string _repoPath;

    public string Title => "UnrealSync";
    public object Icon => Application.Current?.Resources["Icons.UnrealSync"]!;
    public bool IsClosable => true;

    public string TabId { get; }

    public int SortOrder => 100;

    public object ToolbarContent => _viewModel.StatusPanel;

    public object BodyContent => _viewModel;

    public UnrealSyncTab(string repoPath)
    {
        _repoPath = repoPath;
        TabId = $"unrealsync-{Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(repoPath)))[..8].ToLowerInvariant()}";
        _viewModel = new UnrealSyncTabViewModel(repoPath);
    }

    public void OnActivated() => _ = _viewModel.RefreshAsync();
    public void OnDeactivated() { }
    public void Dispose() => _viewModel.Dispose();
}

using System.IO;
using System.Threading.Tasks;

using Avalonia.Threading;

using CommunityToolkit.Mvvm.ComponentModel;

using SourceGit.Models;
using SourceGit.Services;

namespace SourceGit.ViewModels.Tabs.UnrealSync;

public enum SyncTabMode
{
    Detecting,
    FullWorkspace,
    NotUeProject,
    EngineNotFound
}

public class UnrealSyncTabViewModel : ObservableObject
{
    private readonly string _repoPath;
    private SyncTabMode _mode = SyncTabMode.Detecting;

    public StatusPanelViewModel StatusPanel { get; }

    public object? CurrentBody { get; private set; }

    public SyncTabMode Mode
    {
        get => _mode;
        private set => SetProperty(ref _mode, value);
    }

    public UnrealSyncTabViewModel(string repoPath)
    {
        _repoPath = repoPath;
        StatusPanel = new StatusPanelViewModel(repoPath, null);
    }

    public async Task RefreshAsync()
    {
        Mode = SyncTabMode.Detecting;

        await Task.Run(() =>
        {
            var uprojectFiles = Directory.GetFiles(_repoPath, "*.uproject");
            if (uprojectFiles.Length == 0)
            {
                Dispatcher.UIThread.Post(() =>
                {
                    Mode = SyncTabMode.NotUeProject;
                    CurrentBody = new NotUeProjectViewModel();
                });
                return;
            }

            var json = File.ReadAllText(uprojectFiles[0]);
            var meta = UProjectMeta.ParseTolerant(json);
            var enginePath = EngineDetector.Detect(meta, _repoPath);

            Dispatcher.UIThread.Post(() =>
            {
                if (enginePath != null)
                {
                    Mode = SyncTabMode.FullWorkspace;
                    CurrentBody = new StatusPanelViewModel(_repoPath, enginePath);
                }
                else
                {
                    Mode = SyncTabMode.EngineNotFound;
                    CurrentBody = new EngineNotFoundViewModel(meta);
                }
            });
        });
    }

    public void Dispose()
    {
        if (CurrentBody is StatusPanelViewModel statusVm)
        {
            // Cleanup if needed
        }
    }
}

using System;
using System.Reflection;

using Avalonia.Interactivity;

namespace UGSGit.Views
{
    public partial class About : ChromelessWindow
    {
        public About()
        {
            CloseOnESC = true;
            InitializeComponent();

            var assembly = Assembly.GetExecutingAssembly();
            var ver = assembly.GetName().Version;
            if (ver != null)
                TxtVersion.Text = $"{ver.Major}.{ver.Minor:D2}";

            var meta = assembly.GetCustomAttributes<AssemblyMetadataAttribute>();
            foreach (var attr in meta)
            {
                if (attr.Key.Equals("BuildDate", StringComparison.OrdinalIgnoreCase) && DateTime.TryParse(attr.Value, out var date))
                {
                    TxtReleaseDate.Text = App.Text("About.ReleaseDate", Models.DateTimeFormat.Format(date, true));
                    break;
                }
            }

            var informationVersion = assembly.GetCustomAttribute<AssemblyInformationalVersionAttribute>();
            if (informationVersion != null)
            {
                var infoVer = informationVersion.InformationalVersion;
                var idx = infoVer.IndexOf('+');
                if (idx > 0 && infoVer.Length > idx + 11)
                {
                    TxtGitSourceRevision.Text = infoVer.Substring(idx + 1, 10);
                    PnlGitSourceRevision.IsVisible = true;
                }
            }

            var copyright = assembly.GetCustomAttribute<AssemblyCopyrightAttribute>();
            if (copyright != null)
                TxtCopyright.Text = copyright.Copyright;
        }

        private void OnVisitReleaseNotes(object _, RoutedEventArgs e)
        {
            Native.OS.OpenBrowser($"https://github.com/nievesj/UnrealGameSync-Git/releases/tag/v{TxtVersion.Text}");
            e.Handled = true;
        }

        private void OnVisitWebsite(object _, RoutedEventArgs e)
        {
            Native.OS.OpenBrowser("https://github.com/nievesj/UnrealGameSync-Git/");
            e.Handled = true;
        }

        private void OnVisitSourceCode(object _, RoutedEventArgs e)
        {
            Native.OS.OpenBrowser("https://github.com/sourcegit-scm/sourcegit");
            e.Handled = true;
        }
    }
}

